--
-- Name: generate_legacy_style_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_legacy_style_id() RETURNS text
    LANGUAGE sql
    AS $$
  select substring(
           regexp_replace(encode(gen_random_bytes(24), 'base64'), '[^0-9A-Za-z]', '', 'g')
           from 1 for 10
         );
$$;


--
-- Name: immutable_text_array_to_string(text[], text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.immutable_text_array_to_string(text[], text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $_$
  select array_to_string($1, $2);
$_$;


--
-- Name: match_topic_tags(text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.match_topic_tags(topic_names text[]) RETURNS text[]
    LANGUAGE sql STABLE
    SET search_path TO ''
    AS $_$
  select coalesce(array_agg(distinct t.name order by t.name), '{}'::text[])
  from public.tags t
  where case
    -- Single non-canonical value: anchored, whole-tag, case-insensitive
    -- equality (Parse's ^topic:value$ with the /i flag).
    when coalesce(array_length(topic_names, 1), 0) = 1 then
      lower(t.name) = lower('topic:' || topic_names[1])
    -- Two or more: unanchored, case-insensitive contains-match, OR-ed across
    -- the values (Parse's `topic:v1|topic:v2` with the /i flag). strpos on
    -- lower()ed operands is a pure literal substring test -- no pattern
    -- metacharacters, so nothing to escape and no ReDoS surface.
    when coalesce(array_length(topic_names, 1), 0) > 1 then
      exists (
        select 1
        from unnest(topic_names) as tn
        where strpos(lower(t.name), lower('topic:' || tn)) > 0
      )
    -- Empty/NULL input matches nothing.
    else false
  end;
$_$;


